use std::fs;
use std::path::{Path, Display};

fn walk_directory(current_path: &Path) -> std::io::Result<()> {
    let entries = fs::read_dir(current_path)?;
    for entry in entries {
        let entry = entry?;
        let path = entry.path();
        if path.is_dir() {
            walk_directory(&path)?;
        } else if path.is_file() {
                println!("Found file: {}", path.display());
        }
    }
    Ok(())
}

fn main() -> std::io::Result<()> {
    let start_path = Path::new("./test_root");
    if !start_path.exists() {
        println!("Please create a directory named 'test_root' for this example to work.");
        return Ok(());
    }
    walk_directory(start_path)?;
    Ok(())
}

