use std::collections::VecDeque;

struct Heartbeat {
    server_id: u32,
    sequence_number: u64,
    is_valid: bool,
}

fn process_heartbeats(all_heartbeats: Vec<Heartbeat>) -> Vec<u64> {
    let initial_delay = 3;
    let step_interval = 3;

    let results: Vec<u64> = all_heartbeats.into_iter()
        .skip(initial_delay)
        .step_by(step_interval)
        .map(|hb| hb.sequence_number)
        .collect();
    results
}

fn main() {
    let mut deque: VecDeque<Heartbeat> = VecDeque::new();
    for i in 0..15 {
        deque.push_back(Heartbeat { 
            server_id: (i % 3) + 1,
            sequence_number: i as u64 * 10 + (i % 2) as u64,
            is_valid: true
        });
    }

    let heartbeats: Vec<Heartbeat> = deque.into();
    let processed_sequences = process_heartbeats(heartbeats);

    println!("Successfully extracted sequence numbers:");
    for seq in processed_sequences {
        println!("{}", seq);
    }
}

use std::collections::HashMap;

#[derive(Debug)]
struct UserRecord {
    id: u32,
    username: String,
    email: String,
}

fn process_data_chunk(records: Vec<UserRecord>) -> HashMap<u32, String> {
    let mut batch_map = HashMap::new();

    for record in records.into_iter().skip(2).step_by(3) {
        if !record.username.is_empty() {
            batch_map.insert(record.id, format!("Processed: {}", record.email));
        }
    }
    batch_map
}

fn main() {
    let data = vec![ 
        UserRecord { id: 101, username: String::from("A"), email: String::from("a@example.com") },
        UserRecord { id: 102, username: String::from("B"), email: String::from("b@example.com") },
        UserRecord { id: 103, username: String::from("C_Good"), email: String::from("c_good@example.com") },
        UserRecord { id: 104, username: String::from("D"), email: String::from("d@example.com") },
        UserRecord { id: 105, username: String::from("E_Good"), email: String::from("e_good@example.com") },
